// Pega o item de entrada
const entrada = $input.first().json;

// Converte a string de produtos em array
const produtos = JSON.parse(entrada.produtos);

// Data atual no formato YYYY-MM-DD
const hoje = new Date().toISOString().split('T')[0];

// --- FUNÇÃO AJUDANTE ---
// Formata número para: 2 casas decimais e troca ponto por vírgula
const formatarDinheiro = (valor) => {
  const numero = parseFloat(valor || 0);
  return numero.toFixed(2).replace('.', ',');
};

// --- MONTAGEM DO RESUMO PARA OBSERVAÇÃO ---

const textoProdutos = produtos.map(item => {
  return `- ${item.quantidade}x ${item.descricao} | Total: R$ ${formatarDinheiro(item.total_item)}`;
}).join('\n');

const textoPagamentos = entrada.detalhe_pagamentos
  .filter(pg => pg.valor > 0)
  .map(pg => `- ${pg.metodo}: R$ ${formatarDinheiro(pg.valor)}`)
  .join('\n');

const novaObservacao = `${entrada["observação"]}

--------------------------------
TOTAL DO PEDIDO: R$ ${formatarDinheiro(entrada.total_pedido)}
TOTAL PAGO: R$ ${formatarDinheiro(entrada.total_pago)}
TOTAL TROCO: R$ ${formatarDinheiro(entrada.troco_gerado)}

--------------------------------
RESUMO DOS ITENS:
${textoProdutos}

--------------------------------
DETALHE PAGAMENTOS:
${textoPagamentos}
Troco para: R$ ${formatarDinheiro(entrada.troco_para)}
Operador: ${entrada.operador || 'Não informado'}`;

// --- MONTAGEM DO JSON DE SAÍDA ---

const itens = produtos.map(item => ({
  produto: item.id_produto,
  quantidade: item.quantidade,
  precoUnitario: item.total_item 
}));

const resultado = {
  dav: {
    cliente: entrada["código cliente"],
    filial: "1",
    tipoDocumento: 4,
    condicaoPagamento: "1",
    data: hoje,

    extra1: entrada.operador || "",
    extra2: "", 
    extra3: "", 
    extra4: "", 
    extra5: "",
    extra6: "", 
    extra8: "",

    observacao: novaObservacao, 
    vendedor: entrada.entregador,
    itens
  }
};

return [{ json: resultado }];
